import { useState } from 'react';
import axiosInstance from '../axiosConfig';

const MyReservations = () => {
  const [lookupData, setLookupData] = useState({ reservationId: '', customerName: '' });
  const [reservation, setReservation] = useState(null);
  const [editing, setEditing] = useState(false);
  const [editData, setEditData] = useState({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Look up reservation by ID and verify name
  const handleLookup = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setReservation(null);
    try {
      const response = await axiosInstance.get(`/api/reservations/${lookupData.reservationId}`);
      const found = response.data;

      // Verify name matches
      if (found.customerName.toLowerCase() !== lookupData.customerName.toLowerCase()) {
        setError('Name does not match this reservation ID.');
        return;
      }

      setReservation(found);
      setEditData({
        numGuests: found.numGuests,
        reservedDate: found.reservedDate.slice(0, 16)
      });
    } catch (err) {
      setError('Reservation not found. Please check your ID and try again.');
    } finally {
      setLoading(false);
    }
  };

  // Update reservation
  const handleUpdate = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');
    try {
      const response = await axiosInstance.put(
        `/api/reservations/${reservation._id}`,
        editData
      );
      setReservation(response.data.reservation);
      setEditing(false);
      setSuccess('Reservation updated. A confirmation SMS has been sent.');
    } catch (err) {
      setError(err.response?.data?.message || 'Update failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // Cancel reservation
  const handleCancel = async () => {
    if (!window.confirm('Are you sure you want to cancel this reservation?')) return;
    setLoading(true);
    setError('');
    try {
      await axiosInstance.delete(`/api/reservations/${reservation._id}`);
      setReservation(null);
      setSuccess('Your reservation has been cancelled.');
      setLookupData({ reservationId: '', customerName: '' });
    } catch (err) {
      setError('Failed to cancel. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto mt-10 px-4">
      <h1 className="text-3xl font-bold text-center mb-8 text-blue-700">
        My Reservations
      </h1>

      {error && (
        <div className="bg-red-100 text-red-700 p-3 rounded mb-4 text-sm">{error}</div>
      )}
      {success && (
        <div className="bg-green-100 text-green-700 p-3 rounded mb-4 text-sm">{success}</div>
      )}

      {/* Lookup form */}
      {!reservation && (
        <form onSubmit={handleLookup} className="bg-white p-6 shadow rounded">
          <h2 className="text-xl font-semibold mb-4">Find Your Reservation</h2>
          <label className="block text-sm font-medium mb-1">Reservation ID</label>
          <input
            type="text"
            placeholder="Paste your reservation ID"
            value={lookupData.reservationId}
            onChange={(e) => setLookupData({ ...lookupData, reservationId: e.target.value })}
            className="w-full mb-4 p-2 border rounded font-mono"
            required
          />
          <label className="block text-sm font-medium mb-1">Full Name</label>
          <input
            type="text"
            placeholder="Name used when booking"
            value={lookupData.customerName}
            onChange={(e) => setLookupData({ ...lookupData, customerName: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 text-white p-2 rounded hover:bg-blue-700 transition disabled:opacity-50"
          >
            {loading ? 'Looking up...' : 'Find Reservation'}
          </button>
        </form>
      )}

      {/* Reservation details */}
      {reservation && !editing && (
        <div className="bg-white p-6 shadow rounded">
          <h2 className="text-xl font-semibold mb-4">Your Reservation</h2>
          <div className="bg-gray-50 rounded p-4 mb-4">
            <p><span className="font-medium">Name:</span> {reservation.customerName}</p>
            <p><span className="font-medium">Date:</span> {new Date(reservation.reservedDate).toLocaleString()}</p>
            <p><span className="font-medium">Guests:</span> {reservation.numGuests}</p>
            <p><span className="font-medium">Table:</span> {reservation.tableId?.location}</p>
            <p><span className="font-medium">Status:</span>{' '}
              <span className={`font-semibold ${reservation.status === 'confirmed' ? 'text-green-600' : 'text-red-600'}`}>
                {reservation.status}
              </span>
            </p>
          </div>
          <div className="flex gap-3">
            <button
              onClick={() => setEditing(true)}
              className="flex-1 bg-yellow-500 text-white p-2 rounded hover:bg-yellow-600 transition"
            >
              Edit Reservation
            </button>
            <button
              onClick={handleCancel}
              disabled={loading}
              className="flex-1 bg-red-500 text-white p-2 rounded hover:bg-red-600 transition disabled:opacity-50"
            >
              Cancel Reservation
            </button>
          </div>
          <button
            onClick={() => { setReservation(null); setSuccess(''); }}
            className="mt-3 w-full text-sm text-blue-600 hover:underline"
          >
            Look up a different reservation
          </button>
        </div>
      )}

      {/* Edit form */}
      {reservation && editing && (
        <form onSubmit={handleUpdate} className="bg-white p-6 shadow rounded">
          <h2 className="text-xl font-semibold mb-4">Edit Reservation</h2>
          <label className="block text-sm font-medium mb-1">New Date and Time</label>
          <input
            type="datetime-local"
            value={editData.reservedDate}
            onChange={(e) => setEditData({ ...editData, reservedDate: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <label className="block text-sm font-medium mb-1">Number of Guests</label>
          <input
            type="number"
            min="1"
            max="20"
            value={editData.numGuests}
            onChange={(e) => setEditData({ ...editData, numGuests: e.target.value })}
            className="w-full mb-4 p-2 border rounded"
            required
          />
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-green-600 text-white p-2 rounded hover:bg-green-700 transition disabled:opacity-50"
          >
            {loading ? 'Saving...' : 'Save Changes'}
          </button>
          <button
            type="button"
            onClick={() => setEditing(false)}
            className="mt-3 w-full text-sm text-blue-600 hover:underline"
          >
            Cancel
          </button>
        </form>
      )}
    </div>
  );
};

export default MyReservations;
